1	type Item = { type: string };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
4	type QuoteResult = { premium: number };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_RATE = 0.1;
8	
9	const ITEM_BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	};
16	
17	const RUNE_BLOCK_SIZE = 3;
18	const RUNE_BLOCK_BASE_PREMIUM = 60;
19	
20	const premiumFor = (totalBase: number): number =>
21	  totalBase + Math.ceil(totalBase * FIRST_INSURANCE_RATE) + PROCESSING_FEE;
22	
23	const baseFor = (item: Item): number => ITEM_BASE_PREMIUMS[item.type];
24	
25	const isRuneBlock = (items: Item[]): boolean =>
26	  items.length === RUNE_BLOCK_SIZE && items.every((i) => i.type === "rune");
27	
28	const totalBaseFor = (items: Item[]): number => {
29	  if (isRuneBlock(items)) return RUNE_BLOCK_BASE_PREMIUM;
30	  return items.reduce((sum, item) => sum + baseFor(item), 0);
31	};
32	
33	const quoteFor = (step: QuoteStep): QuoteResult => ({
34	  premium: premiumFor(totalBaseFor(step.items)),
35	});
36	
37	export const processScenario = (input: Scenario): { results: QuoteResult[] } => {
38	  return { results: input.steps.map(quoteFor) };
39	};
